### Swift Extensions

Extensions add new functionality to existing types, including types from the standard library or third-party frameworks. They can add computed properties, methods, initializers, subscripts, and protocol conformance.

**Extension Syntax:**

```swift
extension SomeType {
    // New functionality here
}
```

**What Extensions Can Add:**

| Feature | Can Add? | Notes |
|---------|----------|-------|
| Computed properties | Yes | No stored properties |
| Instance methods | Yes | |
| Type methods | Yes | Using `static` |
| Initializers | Yes | Convenience only for classes |
| Subscripts | Yes | |
| Nested types | Yes | |
| Protocol conformance | Yes | |
| Stored properties | No | Use associated objects (ObjC) |

```swift
extension Double {
    // Computed property
    var asCurrency: String {
        return String(format: "$%.2f", self)
    }

    // Computed property
    var squared: Double {
        return self * self
    }

    // Instance method
    func rounded(to places: Int) -> Double {
        let divisor = pow(10.0, Double(places))
        return (self * divisor).rounded() / divisor
    }
}

let price = 19.99
print(price.asCurrency)  // $19.99
print(price.squared)     // 399.6001
print((123.4567).rounded(to: 2))  // 123.46
```

**Extensions on Standard Types:**

```swift
extension String {
    var isEmail: Bool {
        return contains("@") && contains(".")
    }

    func truncate(to length: Int) -> String {
        guard count > length else { return self }
        return prefix(length) + "..."
    }
}

print("test@example.com".isEmail)  // true
print("Hello World".truncate(to: 5))  // Hello...
```

**Adding Protocol Conformance:**

```swift
struct Point {
    var x: Double, y: Double
}

// Conform to Equatable via extension
extension Point: Equatable {
    static func == (lhs: Point, rhs: Point) -> Bool {
        return lhs.x == rhs.x && lhs.y == rhs.y
    }
}

extension Point: CustomStringConvertible {
    var description: String {
        return "(\(x), \(y))"
    }
}
```

> **Key Point:** Extensions cannot override existing functionality. They add new capabilities. Use them to organize code by feature, conform to protocols, or add utilities to existing types.

Use extensions to organize your code into logical sections:

```swift
class MyViewController {
    // Main implementation
}

extension MyViewController: UITableViewDataSource {
    // Table view data source methods
}

extension MyViewController: UITableViewDelegate {
    // Table view delegate methods
}
```

codeExample:
import Foundation

// Extending built-in types
extension Int {
    var isEven: Bool { self % 2 == 0 }
    var isOdd: Bool { !isEven }

    func times(_ action: () -> Void) {
        for _ in 0..<self {
            action()
        }
    }
}

extension Array where Element: Numeric {
    var sum: Element {
        reduce(0, +)
    }

    var average: Double {
        guard !isEmpty else { return 0 }
        return Double(sum as! Int) / Double(count)
    }
}

print("Is 7 even? \(7.isEven)")
print("Is 8 even? \(8.isEven)")

3.times { print("Hello!") }

let numbers = [1, 2, 3, 4, 5]
print("Sum: \(numbers.sum)")

// Extending with Equatable
extension String {
    func isValidPassword() -> Bool {
        count >= 8 && contains { $0.isNumber } && contains { $0.isUppercase }
    }
}

print("Password valid: \(Swift1234".isValidPassword())")
